import jsonfrom openai import OpenAIfrom invoice_agent.tools.extract_invoice import extract_invoice_datafrom invoice_agent.tools.notify import send_notificationclient = OpenAI()def run_invoice_agent(email_path: str, pdf_path: str):    tools = [        {            "type": "function",            "function": {                "name": "extract_invoice_data",                "description": "Extract structured invoice data from email and PDF",                "parameters": {                    "type": "object",                    "properties": {                        "email_path": {"type": "string"},                        "pdf_path": {"type": "string"},                    },                    "required": ["email_path", "pdf_path"],                },            },        },        {            "type": "function",            "function": {                "name": "send_notification",                "description": "Generate outbound notification for Customer Service using extracted invoice fields",                "parameters": {                    "type": "object",                    "properties": {},  # accept flexible object                },            },        },    ]    messages = [        {            "role": "system",            "content": """                    You are an invoice intake automation agent.                                        Workflow:                    1. Call extract_invoice_data first.                    2. Then call send_notification with the extracted structured data.                    3. Do not repeat tools.                    4. Finish after notification.                    """        },        {            "role": "user",            "content": f"Process the invoice located at email_path={email_path} and pdf_path={pdf_path}"        }    ]            extracted_invoice = None        while True:        response = client.chat.completions.create(            model="gpt-5-mini",            messages=messages,            tools=tools,            tool_choice="auto"        )        message = response.choices[0].message        # Append assistant message FIRST        messages.append({            "role": "assistant",            "content": message.content,            "tool_calls": message.tool_calls,        })        if message.tool_calls:            for tool_call in message.tool_calls:                function_name = tool_call.function.name                arguments = json.loads(tool_call.function.arguments)                if function_name == "extract_invoice_data":                    extracted_invoice = extract_invoice_data(**arguments)                    result = extracted_invoice                                elif function_name == "send_notification":                    if extracted_invoice is None:                        raise ValueError("No extracted invoice data available.")                    result = send_notification(extracted_invoice)                else:                    raise ValueError(f"Unknown tool: {function_name}")                # Append tool result                messages.append({                    "role": "tool",                    "tool_call_id": tool_call.id,                    "content": json.dumps(result),                })        else:            return message.content